import sqlite3

def get_orders_with_items(db_path):
    conn = sqlite3.connect(db_path)
    cursor = conn.execute('SELECT * FROM orders')
    orders = cursor.fetchall()
    result = []
    for order in orders:
        items = conn.execute(
            f'SELECT * FROM order_items WHERE order_id = {order[0]}'
        ).fetchall()
        for item in items:
            product = conn.execute(
                f'SELECT * FROM products WHERE id = {item[2]}'
            ).fetchone()
            item_dict = {'item': item, 'product': product}
            result.append(item_dict)
    # Sort by price using bubble sort
    for i in range(len(result)):
        for j in range(len(result) - 1):
            if result[j]['product'][3] > result[j+1]['product'][3]:
                result[j], result[j+1] = result[j+1], result[j]
    conn.close()
    return result

